public int ways(int[][] grid, int m, int n, int i, int j, int k, int sum, int[][][] dp) {
    if (i == m - 1 && j == n - 1) {
        return (sum + grid[i][j]) % k == 0 ? 1 : 0;
    }
    if (dp[i][j][sum] == -1) {
        int ans = 0;
        if (i + 1 < m) ans = (ans + ways(grid, m, n, i + 1, j, k, (sum + grid[i][j]) % k, dp)) % 1000000007;
        if (j + 1 < n) ans = (ans + ways(grid, m, n, i, j + 1, k, (sum + grid[i][j]) % k, dp)) % 1000000007;
        dp[i][j][sum] = ans;
    }
    return dp[i][j][sum];
}

public int waysToReachDivisibleSum(int[][] grid, int k) {
    int m = grid.length, n = grid[0].length;
    int[][][] dp = new int[m][n][k];
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            Arrays.fill(dp[i][j], -1);
        }
    }
    return ways(grid, m, n, 0, 0, k, 0, dp);
}
